const body = $json.body ?? $json;
const sessionId = body.session_id ? String(body.session_id).trim() : '';
const userId = body.user_id ? String(body.user_id).trim() : '';
const email = body.email ? String(body.email).trim().toLowerCase() : null;
const provider = body.provider ? String(body.provider).trim().toLowerCase() : 'email';
const locale = String(body.locale || 'en').toLowerCase().startsWith('ar') ? 'ar' : 'en';
const direction = String(body.direction || (locale === 'ar' ? 'rtl' : 'ltr')).toLowerCase() === 'rtl' ? 'rtl' : 'ltr';
const guestIdentityKey = body.guest_identity_key ? String(body.guest_identity_key).trim() : null;
const sourcePage = body.source_page || 'landing';
const identityKey = userId ? `user:${userId}` : '';
let route = 'ok';
let errorMessage = null;
if (!sessionId) {
  route = 'bad_request';
  errorMessage = 'session_id is required';
} else if (!userId) {
  route = 'bad_request';
  errorMessage = 'user_id is required';
}
return {
  json: {
    request_received_at: new Date().toISOString(),
    db_base_url: 'https://qldgpkqpyfpqfdchozsp.supabase.co',
    session_id: sessionId,
    user_id: userId,
    identity_key: identityKey,
    guest_identity_key: guestIdentityKey,
    auth_email: email,
    auth_provider: provider,
    locale,
    direction,
    source_page: sourcePage,
    day_limit: 10,
    tts_day_limit: 3,
    route,
    error_message: errorMessage
  }
};

return {
  json: {
    http_code: 400,
    ok: false,
    status: 'error',
    message: $json.error_message || 'Invalid request'
  }
};

const base = $('Normalize Upgrade Request').item.json;
const row = Array.isArray($json) ? ($json[0] || null) : $json;
const existingIdentity = row?.identity_key ? String(row.identity_key) : null;
const guestIdentityKey = base.guest_identity_key || (existingIdentity && existingIdentity.startsWith('anon:') ? existingIdentity : null);
return {
  json: {
    ...base,
    session_found: !!row,
    existing_identity_key: existingIdentity,
    guest_identity_key: guestIdentityKey
  }
};

return {
  json: {
    http_code: 404,
    ok: false,
    status: 'error',
    message: 'Session not found'
  }
};

const base = $('Merge Upgrade Context').item.json;
const turnHeaders = $json?.headers || {};
const turnRange = turnHeaders['content-range'] || turnHeaders['Content-Range'] || '';
const turnMatch = String(turnRange).match(/\/(\d+)$/);
const turnsUsedDay = turnMatch ? Number(turnMatch[1]) : (Array.isArray($json?.body) ? $json.body.length : 0);
const ttsResponse = $('Get Auth 24h TTS Previews').item.json || {};
const ttsHeaders = ttsResponse.headers || {};
const ttsRange = ttsHeaders['content-range'] || ttsHeaders['Content-Range'] || '';
const ttsMatch = String(ttsRange).match(/\/(\d+)$/);
const ttsUsedDay = ttsMatch ? Number(ttsMatch[1]) : (Array.isArray(ttsResponse.body) ? ttsResponse.body.length : 0);
const remainingTurnsDay = Math.max(Number(base.day_limit || 10) - (Number.isFinite(turnsUsedDay) ? turnsUsedDay : 0), 0);
const remainingTtsDay = Math.max(Number(base.tts_day_limit || 3) - (Number.isFinite(ttsUsedDay) ? ttsUsedDay : 0), 0);
const imageGenSessionLimit = 4;
return {
  json: {
    http_code: 200,
    ok: true,
    status: 'upgraded',
    session_id: base.session_id,
    message: 'Session upgraded',
    reply_language: base.locale,
    remaining_turns_session: null,
    remaining_turns_day: remainingTurnsDay,
    remaining_tts_previews_session: null,
    remaining_tts_previews_day: remainingTtsDay,
    remaining_image_gen: imageGenSessionLimit,
    tts_available: remainingTtsDay > 0,
    soft_warning_state: 'none',
    cta_state: 'continue_trial',
    cta_payload: {
      title: 'You’re in. Your chat is still here.',
      subtitle: 'Keep going in this same playground with your larger free quota.',
      message: 'Keep going in this same playground with your larger free quota.',
      primary: { type: 'continue_trial', label: 'Keep Exploring' },
      secondary: { type: 'workflow_tour', label: 'See the 2-Min Tour', href: '#solutions' },
      tertiary: { type: 'book_call', label: 'Book a Call', href: '#book' }
    }
  }
};
